mapper.update:
/* 🚀 관리자 전용: 권한(AuthCd) 및 계정 상태(UseYn)까지 수정 가능 */ UPDATE MEMBER
MBR_NAME = #{mbrName}, MBR_NICKNAME = #{mbrNickname}, MBR_TELNO = #{mbrTelno}, MBR_ZIP = #{mbrZip}, MBR_ADDR = #{mbrAddr}, MBR_DADDR = #{mbrDaddr}, MBR_AUTH_CD = #{mbrAuthCd}, MBR_USE_YN = #{mbrUseYn},
MBR_PASSWORD = #{mbrPassword}
WHERE MBR_ID = #{mbrId}

mapper.select:
/* 회원정보 조회 (ID 기준) */
SELECT *
FROM MEMBER
WHERE MBR_ID = #{mbrId}

mapper.update:
/* 회원 탈퇴 (소프트 삭제 및 마스킹) */
UPDATE MEMBER
SET MBR_USE_YN = 'N',
    /* 🚀 탈퇴자 이메일 재가입 불가 및 UQ 충돌 방지 마스킹 */
    MBR_EMAIL = CONCAT('del_', MBR_ID, '_', UNIX_TIMESTAMP(), '@deleted.local'),
    /* 🚀 닉네임 UQ 충돌 방지 마스킹 */
    MBR_NICKNAME = CONCAT('del_', MBR_ID, '_', UNIX_TIMESTAMP()),
    /* 🚀 리프레시 토큰 무효화 */
    MBR_REFRESH_TOKEN = NULL
WHERE MBR_ID = #{mbrId}

mapper.select:
/* 관리자: 전체 회원 목록 조회 */
SELECT 
      MBR_ID, MBR_PASSWORD, MBR_NAME, MBR_NICKNAME, MBR_EMAIL, 
      MBR_TELNO, MBR_ZIP, MBR_ADDR, MBR_DADDR, MBR_PROFILE_FILE_NO, MBR_PROVIDER_CD, 
      MBR_REFRESH_TOKEN, MBR_AUTH_CD, MBR_JOIN_DATE, MBR_LAST_LGN_DATE, MBR_USE_YN
FROM MEMBER;

